import logging
import os
from datetime import datetime
from flask import Flask, request, jsonify

LOG_DIR = os.getenv("LOG_DIR", "logs")
LOG_FILE = os.getenv("LOG_FILE", "webapp.log")
HOST = os.getenv("HOST", "0.0.0.0")
PORT = int(os.getenv("PORT", "8080"))

os.makedirs(LOG_DIR, exist_ok=True)
LOG_PATH = os.path.join(LOG_DIR, LOG_FILE)

app = Flask(__name__)

logger = logging.getLogger("centralized_web_logger")
logger.setLevel(logging.INFO)
file_handler = logging.FileHandler(LOG_PATH)
file_handler.setLevel(logging.INFO)
formatter = logging.Formatter("%(message)s")
file_handler.setFormatter(formatter)
logger.addHandler(file_handler)


def write_log(service, level, message, metadata=None, remote_addr=None):
    timestamp = datetime.utcnow().isoformat() + "Z"
    metadata_str = ""
    if metadata:
        metadata_str = " metadata=%s" % metadata
    line = "[%s] service=%s level=%s remote_addr=%s message=%s%s" % (
        timestamp,
        service,
        level,
        remote_addr,
        message,
        metadata_str,
    )
    logger.info(line)
    return line


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200


@app.route("/log", methods=["POST"])
def log_message():
    data = request.get_json(silent=True) or {}
    service = data.get("service", "unknown-service")
    level = str(data.get("level", "INFO")).upper()
    message = data.get("message", "")
    metadata = data.get("metadata")
    remote_addr = request.headers.get("X-Forwarded-For", request.remote_addr)

    if not message:
        return jsonify({"error": "message is required"}), 400

    line = write_log(service, level, message, metadata, remote_addr)
    return jsonify({"status": "logged", "entry": line}), 201


